// ===== 自动去重：按 name_zh 去重，保留第一条 =====
const _seen = new Set<string>();
export const ARTISTS: Artist[] = ALL_ARTISTS.filter(a => {
  if (_seen.has(a.name_zh)) return false;
  _seen.add(a.name_zh);
  return true;
});

// 按分类分组
export const ARTISTS_BY_CATEGORY = ARTISTS.reduce((acc, artist) => {
  if (!acc[artist.category]) acc[artist.category] = [];
  acc[artist.category].push(artist);
  return acc;
}, {} as Record<string, Artist[]>);

// 热门歌手（hot_score >= 8）
export const HOT_ARTISTS = ARTISTS.filter(a => a.hot_score >= 8);

// 按 ID 查找
export function getArtistById(id: number): Artist | undefined {
  return ARTISTS.find(a => a.id === id);
}

// 按名称搜索
export function searchArtists(query: string): Artist[] {
  const q = query.toLowerCase();
  return ARTISTS.filter(a => 
    a.name_zh.toLowerCase().includes(q) || 
    a.name_en.toLowerCase().includes(q) ||
    a.tags.some(t => t.toLowerCase().includes(q))
  );
}

// 按流派获取歌手（兼容旧接口）
export function getArtistsByGenre(genreId: number): Artist[] {
  return ARTISTS.filter(a => a.genres.includes(genreId));
}

// 动态校验：确保数据非空且无重复ID
if (ARTISTS.length === 0) {
  throw new Error('ARTISTS 数据为空');
}
const artistIds = new Set<number>();
for (const a of ARTISTS) {
  if (artistIds.has(a.id)) {
    throw new Error(`ARTISTS 存在重复 ID: ${a.id}`);
  }
  artistIds.add(a.id);
}
